// This is an optional secondary handler for identity events
// The primary handler is the portal API route
const body = $input.first().json.body || $input.first().json;

const event_type = body.type;
const session = body.data?.object;

if (!session) {
  return [{ json: { skip: true, reason: 'No session data' } }];
}

const applicationId = session.metadata?.application_id;
const status = session.status;

return [{
  json: {
    event_type,
    application_id: applicationId || 'unknown',
    status: status || 'unknown',
    session_id: session.id,
    timestamp_est: new Date().toLocaleString('en-US', {
      timeZone: 'America/New_York',
      dateStyle: 'medium',
      timeStyle: 'short'
    })
  }
}];

